#pragma once

#include "public.h"

#include "message.h"

#include <yt/yt/flow/library/cpp/common/proto/visit.pb.h>

namespace NYT::NFlow {

////////////////////////////////////////////////////////////////////////////////

//! Visit class.
//! Generated by KeyVisitor; carries a single key from the visited state.
struct TVisit
    : public TMessageMeta
{
    TKey Key;
};

void FormatValue(TStringBuilderBase* builder, const TVisit& visit, TStringBuf /*spec*/);

i64 GetVisitByteSize(const TVisit& visit);

void ValidateVisit(const TVisit& visit);

////////////////////////////////////////////////////////////////////////////////

//! Validated input visit with computed size.
//! Consider it as immutable and pass it as TInputVisitConstPtr.
struct TInputVisit
    : public TMessageMetaOwner
    , public TVisit
{
    i64 ByteSize;

    explicit TInputVisit(TVisit&& visit);

    const TMessageMeta& GetMeta() const final;
};

DEFINE_REFCOUNTED_TYPE(TInputVisit);

void FormatValue(TStringBuilderBase* builder, const TInputVisitConstPtr& visit, TStringBuf /*spec*/);

////////////////////////////////////////////////////////////////////////////////

//! Binary serialization for sending visits to the companion (future use).
void ToProto(NProto::TVisit* protoVisit, const TVisit& visit);

void FromProto(TVisit* visit, const NProto::TVisit& protoVisit);

////////////////////////////////////////////////////////////////////////////////

} // namespace NYT::NFlow
